import bcrypt from 'bcryptjs';
import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { env } from './env';
import { db } from './db';

const JWT_SECRET = new TextEncoder().encode(
  env.JWT_SECRET || 'fallback-secret-min-32-characters-long'
);

const SESSION_DURATION = 60 * 60 * 24 * 7; // 7 days

export interface Session {
  id: string;
  userId: string;
  email: string;
  name: string;
  role: 'admin' | 'editor';
  expiresAt: Date;
}

// Hash password with bcrypt
export async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}

// Verify password
export async function verifyPassword(password: string, hashedPassword: string): Promise<boolean> {
  return bcrypt.compare(password, hashedPassword);
}

// Create JWT token
export async function createToken(payload: object): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(JWT_SECRET);
}

// Verify JWT token
export async function verifyToken(token: string): Promise<Session | null> {
  try {
    const { payload } = await jwtVerify(token, JWT_SECRET);
    return payload as Session;
  } catch {
    return null;
  }
}

// Create session
export async function createSession(userId: string, email: string, name: string): Promise<string> {
  const token = await createToken({
    userId,
    email,
    name,
    role: 'admin',
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
  });

  // Store in database
  await db.session.create({
    data: {
      token,
      userId,
      expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
    },
  });

  return token;
}

// Get current session from cookies
export async function getSession(): Promise<Session | null> {
  const cookieStore = await cookies();
  const token = cookieStore.get('admin-session')?.value;

  if (!token) return null;

  const session = await verifyToken(token);
  if (!session) return null;

  // Check if session is expired
  if (new Date() > new Date(session.expiresAt)) {
    await deleteSession(token);
    return null;
  }

  return session;
}

// Delete session
export async function deleteSession(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.delete('admin-session');

  try {
    await db.session.delete({
      where: { token },
    });
  } catch {
    // Session might not exist in DB
  }
}

// Set session cookie
export async function setSessionCookie(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.set('admin-session', token, {
    httpOnly: true,
    secure: env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: SESSION_DURATION,
    path: '/',
  });
}

// Rate limiting for login attempts
const loginAttempts = new Map<string, { count: number; resetAt: number }>();

export function checkRateLimit(identifier: string): boolean {
  const now = Date.now();
  const attempt = loginAttempts.get(identifier);

  if (!attempt || now > attempt.resetAt) {
    loginAttempts.set(identifier, {
      count: 1,
      resetAt: now + 15 * 60 * 1000, // 15 minutes
    });
    return true;
  }

  if (attempt.count >= 5) {
    return false;
  }

  attempt.count++;
  return true;
}

// Clear rate limit
export function clearRateLimit(identifier: string): void {
  loginAttempts.delete(identifier);
}

// Generate secure random token
export function generateSecureToken(length: number = 32): string {
  const chars = 'REDACTED';
  let token = '';
  for (let i = 0; i < length; i++) {
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
}

import { Redis } from '@upstash/redis';
import { env, features } from './env';

// Redis client singleton
let redisClient: Redis | null = null;

export function getRedis(): Redis | null {
  if (!features.redis) return null;
  if (!redisClient) {
    redisClient = new Redis({
      url: env.UPSTASH_REDIS_URL!,
      token: env.UPSTASH_REDIS_TOKEN!,
    });
  }
  return redisClient;
}

// Cache configuration
const DEFAULT_TTL = 60 * 5; // 5 minutes
const LONG_TTL = 60 * 60 * 24; // 24 hours

interface CacheOptions {
  ttl?: number;
  tags?: string[];
}

export async function getCache<T>(key: string): Promise<T | null> {
  const redis = getRedis();
  if (!redis) return null;

  try {
    const value = await redis.get<T>(key);
    return value;
  } catch (error) {
    console.error('Cache get error:', error);
    return null;
  }
}

export async function setCache<T>(
  key: string,
  value: T,
  options: CacheOptions = {}
): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  const { ttl = DEFAULT_TTL, tags = [] } = options;

  try {
    await redis.set(key, value, { ex: ttl });

    // Store tags for invalidation
    if (tags.length > 0) {
      const tagKey = `tags:${key}`;
      await redis.set(tagKey, tags, { ex: ttl });
    }
  } catch (error) {
    console.error('Cache set error:', error);
  }
}

export async function deleteCache(key: string): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  try {
    await redis.del(key);
    await redis.del(`tags:${key}`);
  } catch (error) {
    console.error('Cache delete error:', error);
  }
}

export async function invalidateByTag(tag: string): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  try {
    // Scan all keys and delete those with matching tag
    let cursor = 0;
    do {
      const result = await redis.scan(cursor, { match: 'tags:*' });
      cursor = result[0];
      const keys = result[1];

      for (const tagKey of keys) {
        const tags = await redis.get<string[]>(tagKey);
        if (tags?.includes(tag)) {
          const dataKey = tagKey.replace('tags:', '');
          await redis.del(dataKey);
          await redis.del(tagKey);
        }
      }
    } while (cursor !== 0);
  } catch (error) {
    console.error('Cache invalidation error:', error);
  }
}

// In-memory fallback for when Redis is unavailable
const memoryCache = new Map<string, { value: unknown; expires: number }>();

export function getMemoryCache<T>(key: string): T | null {
  const item = memoryCache.get(key);
  if (!item) return null;
  if (Date.now() > item.expires) {
    memoryCache.delete(key);
    return null;
  }
  return item.value as T;
}

export function setMemoryCache<T>(
  key: string,
  value: T,
  ttl: number = DEFAULT_TTL
): void {
  memoryCache.set(key, {
    value,
    expires: Date.now() + ttl * 1000,
  });
}

// Cache wrapper for expensive operations
export async function cacheWrap<T>(
  key: string,
  fn: () => Promise<T>,
  options: CacheOptions = {}
): Promise<T> {
  // Try Redis first
  let cached = await getCache<T>(key);
  if (cached !== null) return cached;

  // Fallback to memory cache
  cached = getMemoryCache<T>(key);
  if (cached !== null) return cached;

  // Execute function
  const result = await fn();

  // Store in both caches
  await setCache(key, result, options);
  setMemoryCache(key, result, options.ttl);

  return result;
}

