      setMatrixChars(prev => prev.map(() => 
        Math.random() > 0.7 
          ? KATAKANA[Math.floor(Math.random() * KATAKANA.length)]
          : prev[Math.floor(Math.random() * prev.length)]
      ));
    }, 100);

    // Transition to build phase
