      setPhase('build');
      clearInterval(interval);
    }, 1000);

    return () => {
      clearInterval(interval);
      clearTimeout(timeout);
    };
  }, [isVisible, prefersReducedMotion]);

  // Build phase - type out ASCII art
  useEffect(() => {
    if (phase !== 'build' || prefersReducedMotion) return;

    const lines = ASCII_NAME.split('\n').filter(line => line.trim());

    const typeInterval = setInterval(() => {
      setTypedLines(prev => {
        if (currentLine >= lines.length) {
          clearInterval(typeInterval);
          setTimeout(() => setPhase('reveal'), 500);
          return prev;
        }

        const line = lines[currentLine];
        const currentTyped = prev[currentLine] || '';

        if (currentTyped.length < line.length) {
          const next = [...prev];
          next[currentLine] = line.slice(0, currentTyped.length + 3);
          return next;
        } else {
          setCurrentLine(currentLine + 1);
          return [...prev, line];
        }
      });
    }, 30);

    return () => clearInterval(typeInterval);
  }, [phase, currentLine, prefersReducedMotion]);

  // Progress bar animation
  useEffect(() => {
    if (phase !== 'reveal') return;

    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setPhase('fade'), 500);
          return 100;
        }
        return prev + 2;
      });
    }, 50);

    return () => clearInterval(interval);
  }, [phase]);

  // Role rotation
  useEffect(() => {
    if (phase !== 'reveal') return;

    const interval = setInterval(() => {
      setCurrentRole(prev => (prev + 1) % ROLES.length);
    }, 800);

    return () => clearInterval(interval);
  }, [phase]);

  // Complete splash
  useEffect(() => {
    if (phase !== 'fade') return;

    const timeout = setTimeout(() => {
      sessionStorage.setItem('splash-seen', 'true');
      setIsVisible(false);
      onComplete?.();
    }, 500);

    return () => clearTimeout(timeout);
  }, [phase, onComplete]);

  const handleSkip = useCallback(() => {
    sessionStorage.setItem('splash-seen', 'true');
    setIsVisible(false);
    onComplete?.();
  }, [onComplete]);

  // Skip on escape key
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') handleSkip();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleSkip]);

  if (!isVisible) return null;

  // Reduced motion version - simple fade
  if (prefersReducedMotion) {
    return (
      <motion.div
        initial={{ opacity: 1 }}
        animate={{ opacity: 0 }}
        transition={{ duration: 0.5, delay: 0.5 }}
        className="fixed inset-0 z-[9999] bg-background flex items-center justify-center"
        onClick={handleSkip}
      >
        <div className="text-center">
          <p className="font-mono text-sm text-muted-foreground">Loading...</p>
        </div>
      </motion.div>
    );
  }

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.5 }}
          className="fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center overflow-hidden cursor-pointer"
          onClick={handleSkip}
        >
          {/* Matrix Rain Background */}
          {phase === 'matrix' && (
            <motion.div
              initial={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 grid grid-cols-[repeat(15,1fr)] gap-1 p-8 pointer-events-none"
            >
              {matrixChars.map((char, i) => (
                <motion.span
                  key={i}
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: [0, 1, 0.3], y: 0 }}
                  transition={{ duration: 0.5, delay: i * 0.01 }}
                  className="font-mono text-green-500/40 text-lg"
                  style={{
                    textShadow: '0 0 10px rgba(34, 197, 94, 0.5)',
                  }}
                >
                  {char}
                </motion.span>
              ))}
            </motion.div>
          )}

          {/* Main Content */}
          <div className="relative z-10 text-center px-4">
            {/* Terminal Header */}
            <motion.div
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              className="mb-8"
            >
              <div className="inline-flex items-center gap-2 px-4 py-2 border border-green-500/30 rounded-lg bg-green-500/5">
                <div className="flex gap-1.5">
                  <div className="w-2.5 h-2.5 rounded-full bg-red-500/60" />
                  <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/60" />
                  <div className="w-2.5 h-2.5 rounded-full bg-green-500/60" />
                </div>
                <span className="font-mono text-xs text-green-500/70">
                  douglas-mitchell-system-v4.2.0
                </span>
              </div>
            </motion.div>

            {/* ASCII Art */}
            {(phase === 'build' || phase === 'reveal' || phase === 'fade') && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-6"
              >
                <pre className="font-mono text-[6px] sm:text-[8px] md:text-[10px] lg:text-xs text-green-500 leading-none tracking-tighter whitespace-pre overflow-hidden">
                  {typedLines.map((line, i) => (
                    <motion.div
                      key={i}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.05 }}
                    >
                      {line}
                    </motion.div>
                  ))}
                </pre>
              </motion.div>
            )}

            {/* Subtitle */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-8"
              >
                <div className="flex items-center justify-center gap-4">
                  <span className="font-mono text-green-500/30">{'◄'}</span>
                  <span className="font-mono text-lg text-green-400 tracking-widest">
                    {SUBTITLE}
                  </span>
                  <span className="font-mono text-green-500/30">{'►'}</span>
                </div>
              </motion.div>
            )}

            {/* Rotating Role */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-8 h-8"
              >
                <div className="flex items-center justify-center gap-3">
                  <span className="font-mono text-xs text-green-500/50">$</span>
                  <motion.span
                    key={currentRole}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    className="font-mono text-sm text-green-400"
                  >
                    {ROLES[currentRole]}
                  </motion.span>
                  <motion.span
                    animate={{ opacity: [1, 0] }}
                    transition={{ duration: 0.5, repeat: Infinity }}
                    className="font-mono text-green-500"
                  >
                    ▊
                  </motion.span>
                </div>
              </motion.div>
            )}

            {/* Progress Bar */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="w-64 sm:w-80 mx-auto"
              >
                <div className="flex items-center gap-2 mb-2">
                  <span className="font-mono text-xs text-green-500/50">loading...</span>
                  <span className="font-mono text-xs text-green-400">{progress}%</span>
