{"success":true,"content":"import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { getSession } from '@/lib/auth';
import { logActivity } from '@/lib/activity';
import { getClientIp } from '@/lib/request';
import { rateLimit } from '@/lib/rate-limit';
import { deleteStoredAsset, formatFileSize, getFileCategory, processFileUpload } from '@/lib/upload';

// POST /api/upload - Upload files
export async function POST(request: NextRequest) {
  try {
    // Check authentication
    const session = await getSession();
    if (!session) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Parse form data
    const formData = await request.formData();
    const files = formData.getAll('files') as File[];

    if (!files || files.length === 0) {
      return NextResponse.json(
        { error: 'No files provided' },
        { status: 400 }
      );
    }

    const uploadLimit = rateLimit(`${session.userId}:${getClientIp(request)}`, {
      limit: 20,
      windowMs: 15 * 60 * 1000,
      prefix: 'upload',
    });

    if (!uploadLimit.allowed) {
      return NextResponse.json(
        { error: 'Upload rate limit exceeded. Please wait before trying again.' },
        { status: 429 }
      );
    }

    // Process each file
    const results = await Promise.all(
      files.map(async (file) => {
        const uploadResult = await processFileUpload(file);

        if (!uploadResult.success) {
          return {
            success: false,
            originalName: file.name,
            error: uploadResult.error,
          };
        }

        // Save to database
        const media = await db.media.create({
          data: {
            id: uploadResult.id,
            filename: uploadResult.filename!,
            originalName: uploadResult.originalName,
            mimeType: uploadResult.mimeType,
            category: getFileCategory(uploadResult.mimeType),
            size: uploadResult.size,
            width: uploadResult.width,
            height: uploadResult.height,
            duration: uploadResult.duration,
            url: uploadResult.url!,
            thumbnailUrl: uploadResult.thumbnailUrl,
            uploadedById: session.userId,
          },
        });

        return {
          success: true,
          media: {
            id: media.id,
            filename: media.filename,
            originalName: media.originalName,
            url: media.url,
            thumbnailUrl: media.thumbnailUrl,
            category: media.category,
            size: formatFileSize(media.size),
            width: media.width,
            height: media.height,
          },
        };
      })
    );

    const successful = results.filter(r => r.success);
    const failed = results.filter(r => !r.success);

    if (successful.length > 0) {
      await logActivity({
        action: 'upload',
        resource: 'media',
        userId: session.userId,
        request,
        details: {
          uploaded: successful.length,
          failed: failed.length,
        },
      });
    }

    return NextResponse.json({
      success: true,
      uploaded: successful.length,
      failed: failed.length,
      results,
    });
  } catch (error) {
    console.error('Upload error:', error);
    return NextResponse.json(
      { error: 'Failed to process upload' },
      { status: 500 }
    );
  }
}

// GET /api/upload - List media files
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const category = searchParams.get('category');
    const folder = searchParams.get('folder');
    const page = Math.max(parseInt(searchParams.get('page') || '1', 10), 1);
    const limit = Math.min(Math.max(parseInt(searchParams.get('limit') || '20', 10), 1), 100);
    const search = searchParams.get('search');

    // Build where clause
    const where: any = {};
    if (category) where.category = category;
    if (folder) where.folder = folder;
    if (search) {
      where.OR = [
        { originalName: { contains: search, mode: 'insensitive' } },
        { tags: { contains: search, mode: 'insensitive' } },
      ];
    }

    // Get total count
    const total = await db.media.count({ where });

    // Get media files
    const media = await db.media.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      skip: (page - 1) * limit,
      take: limit,
      include: {
        _count: {
          select: {
            articleUsages: true,
            projectUsages: true,
          },
        },
      },
    });

    return NextResponse.json({
      success: true,
      media,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error('Media list error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch media' },
      { status: 500 }
    );
  }
}

// DELETE /api/upload - Delete media files
export async function DELETE(request: NextRequest) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { ids } = body;

    if (!ids || !Array.isArray(ids) || ids.length === 0) {
      return NextResponse.json(
        { error: 'No media IDs provided' },
        { status: 400 }
      );
    }

    const mediaItems = await db.media.findMany({
      where: { id: { in: ids } },
      select: {
        id: true,
        url: true,
        thumbnailUrl: true,
      },
    });

    const result = await db.media.deleteMany({
      where: { id: { in: ids } },
    });

    await Promise.all(
      mediaItems.flatMap((item) => [
        deleteStoredAsset(item.url),
        deleteStoredAsset(item.thumbnailUrl),
      ])
    );

    await logActivity({
      action: 'delete',
      resource: 'media',
      userId: session.userId,
      request,
      details: {
        deleted: result.count,
      },
    });

    return NextResponse.json({
      success: true,
      deleted: result.count,
    });
  } catch (error) {
    console.error('Media delete error:', error);
    return NextResponse.json(
      { error: 'Failed to delete media' },
      { status: 500 }
    );
  }
}
