import { Redis } from '@upstash/redis';
import { env, features } from './env';

// Redis client singleton
let redisClient: Redis | null = null;

export function getRedis(): Redis | null {
  if (!features.redis) return null;
  if (!redisClient) {
    redisClient = new Redis({
      url: env.UPSTASH_REDIS_URL!,
      token: env.UPSTASH_REDIS_TOKEN!,
    });
  }
  return redisClient;
}

// Cache configuration
const DEFAULT_TTL = 60 * 5; // 5 minutes
const LONG_TTL = 60 * 60 * 24; // 24 hours

interface CacheOptions {
  ttl?: number;
  tags?: string[];
}

export async function getCache<T>(key: string): Promise<T | null> {
  const redis = getRedis();
  if (!redis) return null;

  try {
    const value = await redis.get<T>(key);
    return value;
  } catch (error) {
    console.error('Cache get error:', error);
    return null;
  }
}

export async function setCache<T>(
  key: string,
  value: T,
  options: CacheOptions = {}
): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  const { ttl = DEFAULT_TTL, tags = [] } = options;

  try {
    await redis.set(key, value, { ex: ttl });

    // Store tags for invalidation
    if (tags.length > 0) {
      const tagKey = `tags:${key}`;
      await redis.set(tagKey, tags, { ex: ttl });
    }
  } catch (error) {
    console.error('Cache set error:', error);
  }
}

export async function deleteCache(key: string): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  try {
    await redis.del(key);
    await redis.del(`tags:${key}`);
  } catch (error) {
    console.error('Cache delete error:', error);
  }
}

export async function invalidateByTag(tag: string): Promise<void> {
  const redis = getRedis();
  if (!redis) return;

  try {
    // Scan all keys and delete those with matching tag
    let cursor = 0;
    do {
      const result = await redis.scan(cursor, { match: 'tags:*' });
      cursor = result[0];
      const keys = result[1];

      for (const tagKey of keys) {
        const tags = await redis.get<string[]>(tagKey);
        if (tags?.includes(tag)) {
          const dataKey = tagKey.replace('tags:', '');
          await redis.del(dataKey);
          await redis.del(tagKey);
        }
      }
    } while (cursor !== 0);
  } catch (error) {
    console.error('Cache invalidation error:', error);
  }
}

// In-memory fallback for when Redis is unavailable
const memoryCache = new Map<string, { value: unknown; expires: number }>();

export function getMemoryCache<T>(key: string): T | null {
  const item = memoryCache.get(key);
  if (!item) return null;
  if (Date.now() > item.expires) {
    memoryCache.delete(key);
    return null;
  }
  return item.value as T;
}

export function setMemoryCache<T>(
  key: string,
  value: T,
  ttl: number = DEFAULT_TTL
): void {
  memoryCache.set(key, {
    value,
    expires: Date.now() + ttl * 1000,
  });
}

// Cache wrapper for expensive operations
export async function cacheWrap<T>(
  key: string,
  fn: () => Promise<T>,
  options: CacheOptions = {}
): Promise<T> {
  // Try Redis first
  let cached = await getCache<T>(key);
  if (cached !== null) return cached;

  // Fallback to memory cache
  cached = getMemoryCache<T>(key);
  if (cached !== null) return cached;

  // Execute function
  const result = await fn();

  // Store in both caches
  await setCache(key, result, options);
  setMemoryCache(key, result, options.ttl);

  return result;
}

// Cache keys generator
export const cacheKeys = {
  article: (slug: string) => `article:${slug}`,
  articles: (page: number, limit: number) => `articles:${page}:${limit}`,
  projects: () => 'projects',
  certifications: () => 'certifications',
  book: () => 'book',
  siteConfig: (key: string) => `config:${key}`,
  analytics: (period: string) => `analytics:${period}`,
  media: (id: string) => `media:${id}`,
  user: (id: string) => `user:${id}`,
  session: (token: string) => `session:${token}`,
};

import { z } from 'zod';

const envSchema = z.object({
  // Database
  DATABASE_URL: z.string().default('file:./dev.db'),

  // Auth
  ADMIN_PASSWORD: z.string().min(8).optional(),
  JWT_SECRET: z.string().min(32).optional(),

  // Passkeys (WebAuthn)
  PASSKEY_RP_ID: z.string().optional(),
  PASSKEY_RP_NAME: z.string().default('Douglas Mitchell Portfolio'),
  PASSKEY_EXPECTED_ORIGINS: z.string().optional(),

  // Redis/Cache
  UPSTASH_REDIS_URL: z.string().optional(),
  UPSTASH_REDIS_TOKEN: z.string().optional(),

  // Storage
  STORAGE_PROVIDER: z.enum(['local', 's3', 'r2']).default('local'),
  S3_BUCKET: z.string().optional(),
  S3_REGION: z.string().default('us-east-1'),
  S3_ACCESS_KEY: z.string().optional(),
  S3_SECRET_KEY: z.string().optional(),

  // Upload limits
  MAX_FILE_SIZE: z.string().default('50'), // MB
  UPLOAD_DIR: z.string().default('./public/uploads'),

  // App config
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
  NEXT_PUBLIC_SITE_URL: z.string().url().default('https://douglasmitchell.info'),

  // Features
  ENABLE_PASSKEYS: z.string().default('true'),
  ENABLE_ANALYTICS: z.string().default('false'),

  // Email
  SMTP_HOST: z.string().optional(),
  SMTP_PORT: z.string().default('587'),
  SMTP_USER: z.string().optional(),
  SMTP_PASS: z.string().optional(),
  FROM_EMAIL: z.string().email().optional(),
});

let validatedEnv: z.infer<typeof envSchema> | null = null;

export function getEnv() {
  if (validatedEnv) return validatedEnv;

  try {
    validatedEnv = envSchema.parse(process.env);
    return validatedEnv;
  } catch (error) {
    if (error instanceof z.ZodError) {
      console.error('Environment validation failed:');
      error.errors.forEach((err) => {
        console.error(`  - ${err.path.join('.')}: ${err.message}`);
      });
    }
    throw new Error('Invalid environment variables');
  }
}

// Type-safe env export
export const env = getEnv();

// Feature flags
export const features = {
  passkeys: env.ENABLE_PASSKEYS === 'true' && env.ADMIN_PASSWORD,
  analytics: env.ENABLE_ANALYTICS === 'true',
  email: env.SMTP_HOST && env.SMTP_USER && env.SMTP_PASS,
  s3: env.STORAGE_PROVIDER === 's3' && env.S3_BUCKET && env.S3_ACCESS_KEY,
  redis: env.UPSTASH_REDIS_URL && env.UPSTASH_REDIS_TOKEN,
} as const;

// WebAuthn/Passkey utilities using simple-webauthn
import {
  generateRegistrationOptions,
  verifyRegistrationResponse,
