} from '@simplewebauthn/server';
import type {
  PublicKeyCredentialCreationOptionsJSON,
  PublicKeyCredentialRequestOptionsJSON,
  RegistrationResponseJSON,
  AuthenticationResponseJSON,
} from '@simplewebauthn/types';

// Relying Party configuration
const RP_ID = process.env.PASSKEY_RP_ID || 'localhost';
const RP_NAME = process.env.PASSKEY_RP_NAME || 'Douglas Mitchell Portfolio';
const EXPECTED_ORIGINS = process.env.PASSKEY_EXPECTED_ORIGINS?.split(',') || [
  'http://localhost:3000',
  'https://douglasmitchell.info',
];

// Generate options for registering a new passkey
export async function createRegistrationOptions(
  userId: string,
  userEmail: string,
  userName: string,
  existingCredentialIds: string[] = []
): Promise<PublicKeyCredentialCreationOptionsJSON> {
  const options = await generateRegistrationOptions({
    rpName: RP_NAME,
    rpID: RP_ID,
    userID: userId,
    userName: userEmail,
    userDisplayName: userName,
    attestationType: 'none',
    excludeCredentials: existingCredentialIds.map(id => ({
      id,
      type: 'public-key',
    })),
    authenticatorSelection: {
      residentKey: 'preferred',
      userVerification: 'preferred',
      authenticatorAttachment: 'platform', // Prefer platform authenticators (Touch ID, Windows Hello)
    },
  });

  return options;
}

// Verify registration response from client
export async function verifyRegistration(
  response: RegistrationResponseJSON,
  expectedChallenge: string
): Promise<{
  verified: boolean;
  registrationInfo?: {
    credentialID: string;
    credentialPublicKey: Uint8Array;
    counter: number;
  };
  error?: string;
}> {
  try {
    const verification = await verifyRegistrationResponse({
      response,
      expectedChallenge,
      expectedOrigin: EXPECTED_ORIGINS,
      expectedRPID: RP_ID,
    });

    if (verification.verified && verification.registrationInfo) {
      return {
        verified: true,
        registrationInfo: {
          credentialID: verification.registrationInfo.credentialID,
          credentialPublicKey: verification.registrationInfo.credentialPublicKey,
          counter: verification.registrationInfo.counter,
        },
      };
    }

    return { verified: false, error: 'Registration verification failed' };
  } catch (error) {
    console.error('Registration verification error:', error);
    return { verified: false, error: 'Registration verification failed' };
  }
}

// Generate options for authenticating with a passkey
export async function createAuthenticationOptions(
  credentialIds: string[]
): Promise<PublicKeyCredentialRequestOptionsJSON> {
  const options = await generateAuthenticationOptions({
    rpID: RP_ID,
    allowCredentials: credentialIds.map(id => ({
      id,
      type: 'public-key',
    })),
    userVerification: 'preferred',
  });

  return options;
}

// Verify authentication response from client
export async function verifyAuthentication(
  response: AuthenticationResponseJSON,
  expectedChallenge: string,
  credential: {
    id: string;
    publicKey: Uint8Array;
    counter: number;
  }
): Promise<{
  verified: boolean;
  newCounter?: number;
  error?: string;
}> {
  try {
    const verification = await verifyAuthenticationResponse({
      response,
      expectedChallenge,
      expectedOrigin: EXPECTED_ORIGINS,
      expectedRPID: RP_ID,
      authenticator: {
        credentialID: credential.id,
        credentialPublicKey: credential.publicKey,
        counter: credential.counter,
      },
    });

    if (verification.verified) {
      return {
        verified: true,
        newCounter: verification.authenticationInfo.newCounter,
      };
    }

    return { verified: false, error: 'Authentication verification failed' };
  } catch (error) {
    console.error('Authentication verification error:', error);
    return { verified: false, error: 'Authentication verification failed' };
  }
}

// Base64URL encoding helpers
export function base64URLDecode(base64url: string): Uint8Array {
  const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function base64URLEncode(buffer: Uint8Array): string {
  const binary = String.fromCharCode(...buffer);
  const base64 = btoa(binary);
  return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

