import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { createRegistrationOptions } from '@/lib/passkeys';
import { env } from '@/lib/env';

// POST /api/admin/passkey/register/options
// Generate registration options for a new passkey
export async function POST(request: NextRequest) {
  try {
    // Check if passkeys are enabled
    if (!env.ENABLE_PASSKEYS) {
      return NextResponse.json(
        { error: 'Passkey authentication is not enabled' },
        { status: 400 }
      );
    }

    const body = await request.json();
    const { email } = body;

    if (!email) {
      return NextResponse.json(
        { error: 'Email is required' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
      include: { passkeys: true },
    });

    if (!user) {
      // Don't reveal if user exists for security
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Get existing credential IDs to exclude
    const existingCredentialIds = user.passkeys.map(p => p.credentialId);

    // Generate registration options
    const options = await createRegistrationOptions(
      user.id,
      user.email,
      user.name || user.email,
      existingCredentialIds
    );

    // Store challenge temporarily (in production, use Redis)
    // For now, we'll include it in the response and expect it back
    // In a real app, store this server-side with an expiry

    return NextResponse.json(options);
  } catch (error) {
    console.error('Passkey registration options error:', error);
    return NextResponse.json(
      { error: 'Failed to generate registration options' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { verifyRegistration, base64URLDecode } from '@/lib/passkeys';
import type { RegistrationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/register/verify
// Verify and store a new passkey
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response, expectedChallenge, deviceName } = body;

    if (!email || !response || !expectedChallenge) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Verify the registration response
    const verification = await verifyRegistration(
      response as RegistrationResponseJSON,
      expectedChallenge
    );

    if (!verification.verified || !verification.registrationInfo) {
      return NextResponse.json(
        { error: verification.error || 'Registration verification failed' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Store the credential
    const { credentialID, credentialPublicKey, counter } = verification.registrationInfo;

    await db.passkeyCredential.create({
      data: {
        credentialId: credentialID,
        userId: user.id,
        publicKey: Buffer.from(credentialPublicKey),
        counter,
        deviceType: response.authenticatorAttachment || 'cross-platform',
        deviceName: deviceName || 'Unknown Device',
      },
    });

    return NextResponse.json({
      success: true,
      message: 'Passkey registered successfully',
    });
  } catch (error) {
    console.error('Passkey registration verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey registration' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { createAuthenticationOptions } from '@/lib/passkeys';

// POST /api/admin/passkey/auth/options
// Generate authentication options for passkey login
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email } = body;

    if (!email) {
      return NextResponse.json(
        { error: 'Email is required' },
        { status: 400 }
      );
    }

    // Find user and their passkeys
    const user = await db.adminUser.findUnique({
      where: { email },
      include: { passkeys: true },
    });

    if (!user || user.passkeys.length === 0) {
      // Don't reveal if user exists or has passkeys
      return NextResponse.json(
        { error: 'No passkeys found for this user' },
        { status: 404 }
      );
    }

    // Get credential IDs
    const credentialIds = user.passkeys.map(p => p.credentialId);

    // Generate authentication options
    const options = await createAuthenticationOptions(credentialIds);

    return NextResponse.json(options);
  } catch (error) {
    console.error('Passkey authentication options error:', error);
    return NextResponse.json(
      { error: 'Failed to generate authentication options' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { verifyAuthentication } from '@/lib/passkeys';
import { createSession, setSessionCookie } from '@/lib/auth';
import type { AuthenticationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/auth/verify
// Verify passkey authentication and create session
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response, expectedChallenge } = body;

    if (!email || !response || !expectedChallenge) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Find the credential
    const credentialId = response.id;
    const passkey = await db.passkeyCredential.findUnique({
      where: { credentialId },
      include: { user: true },
    });

    if (!passkey || passkey.user.email !== email) {
      return NextResponse.json(
        { error: 'Invalid credential' },
        { status: 401 }
      );
    }

    // Verify the authentication response
    const verification = await verifyAuthentication(
      response as AuthenticationResponseJSON,
      expectedChallenge,
      {
        id: passkey.credentialId,
        publicKey: new Uint8Array(passkey.publicKey),
        counter: passkey.counter,
      }
    );

    if (!verification.verified) {
      return NextResponse.json(
        { error: verification.error || 'Authentication failed' },
        { status: 401 }
      );
    }

    // Update counter to prevent replay attacks
    if (verification.newCounter !== undefined) {
      await db.passkeyCredential.update({
        where: { id: passkey.id },
        data: {
          counter: verification.newCounter,
          lastUsedAt: new Date(),
        },
      });
    }

    // Update user's last login
    await db.adminUser.update({
      where: { id: passkey.userId },
      data: { lastLoginAt: new Date() },
    });

    // Create session
    const token = await createSession(
      passkey.userId,
      passkey.user.email,
      passkey.user.name || 'Admin'
    );
    await setSessionCookie(token);

    return NextResponse.json({
      success: true,
      user: {
        id: passkey.userId,
        email: passkey.user.email,
        name: passkey.user.name,
      },
    });
  } catch (error) {
    console.error('Passkey authentication verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey authentication' },
      { status: 500 }
    );
  }
}

