// Generate registration options for a new passkey
export async function POST(request: NextRequest) {
  try {
    // Check if passkeys are enabled
    if (env.ENABLE_PASSKEYS !== 'true') {
      return NextResponse.json(
        { error: 'Passkey authentication is not enabled' },
        { status: 400 }
      );
    }

    const body = await request.json();
    const { email } = body;

    if (!email) {
      return NextResponse.json(
        { error: 'Email is required' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
      include: { passkeys: true },
    });

    if (!user) {
      // Don't reveal if user exists for security
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Get existing credential IDs to exclude
    const existingCredentialIds = user.passkeys.map(p => p.credentialId);

    // Generate registration options
    const options = await createRegistrationOptions(
      user.id,
      user.email,
      user.name || user.email,
      existingCredentialIds
    );

    setPasskeyChallenge('register', email, options.challenge);

    return NextResponse.json(options);
  } catch (error) {
    console.error('Passkey registration options error:', error);
    return NextResponse.json(
      { error: 'Failed to generate registration options' },
      { status: 500 }
    );
  }
}
