{"success":true,"content":"import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { consumePasskeyChallenge } from '@/lib/passkey-challenges';
import { verifyRegistration } from '@/lib/passkeys';
import type { RegistrationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/register/verify
// Verify and store a new passkey
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response, deviceName } = body;

    if (!email || !response) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    const expectedChallenge = consumePasskeyChallenge('register', email);
    if (!expectedChallenge) {
      return NextResponse.json(
        { error: 'Registration challenge expired. Please try again.' },
        { status: 400 }
      );
    }

    // Verify the registration response
    const verification = await verifyRegistration(
      response as RegistrationResponseJSON,
      expectedChallenge
    );

    if (!verification.verified || !verification.registrationInfo) {
      return NextResponse.json(
        { error: verification.error || 'Registration verification failed' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Store the credential
    const { credentialID, credentialPublicKey, counter } = verification.registrationInfo;

    await db.passkeyCredential.create({
      data: {
        credentialId: credentialID,
        userId: user.id,
        publicKey: Buffer.from(credentialPublicKey),
        counter,
        deviceType: response.authenticatorAttachment || 'cross-platform',
        deviceName: deviceName || 'Unknown Device',
      },
    });

    return NextResponse.json({
      success: true,
      message: 'Passkey registered successfully',
    });
  } catch (error) {
    console.error('Passkey registration verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey registration' },
      { status: 500 }
    );
  }
}
