import type { AuthenticationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/auth/verify
// Verify passkey authentication and create session
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response } = body;

    if (!email || !response) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    const expectedChallenge = consumePasskeyChallenge('auth', email);
    if (!expectedChallenge) {
      return NextResponse.json(
        { error: 'Authentication challenge expired. Please try again.' },
        { status: 400 }
      );
    }

    // Find the credential
    const credentialId = response.id;
    const passkey = await db.passkeyCredential.findUnique({
      where: { credentialId },
      include: { user: true },
    });

    if (!passkey || passkey.user.email !== email) {
      return NextResponse.json(
        { error: 'Invalid credential' },
        { status: 401 }
      );
    }

    // Verify the authentication response
    const verification = await verifyAuthentication(
      response as AuthenticationResponseJSON,
      expectedChallenge,
      {
        id: passkey.credentialId,
        publicKey: new Uint8Array(passkey.publicKey),
        counter: passkey.counter,
      }
    );

    if (!verification.verified) {
      return NextResponse.json(
        { error: verification.error || 'Authentication failed' },
        { status: 401 }
      );
    }

    // Update counter to prevent replay attacks
    if (verification.newCounter !== undefined) {
      await db.passkeyCredential.update({
        where: { id: passkey.id },
        data: {
          counter: verification.newCounter,
          lastUsedAt: new Date(),
        },
      });
    }

    // Update user's last login
    await db.adminUser.update({
      where: { id: passkey.userId },
      data: { lastLoginAt: new Date() },
    });

    // Create session
    const token = await createSession(
      passkey.userId,
      passkey.user.email,
      passkey.user.name || 'Admin'
    );
    await setSessionCookie(token);

    return NextResponse.json({
      success: true,
      user: {
        id: passkey.userId,
        email: passkey.user.email,
        name: passkey.user.name,
      },
    });
  } catch (error) {
    console.error('Passkey authentication verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey authentication' },
      { status: 500 }
    );
  }
}
